from hexagen import Game, Tile
from constants import HEIGHT, WIDTH, COLORS, DIRECTIONS
with Game() as g:
    vertical_column = 10
    vertical_green_column_tiles = []
    for row in range(1, HEIGHT + 1):
        tile = Tile(row, vertical_column)
        tile.draw("green")
        vertical_green_column_tiles.append(tile)

    red_start_tile = Tile(HEIGHT, 1)
    red_end_tile = Tile(1, WIDTH)
    red_diagonal_tiles = g.line_between(red_start_tile, red_end_tile)
    for tile in red_diagonal_tiles:
        if tile.color == "green":
            tile.draw("green")
        else:
            tile.draw("red")

    blue_start_tile = Tile(1, 1)
    blue_end_tile = Tile(HEIGHT - 1, WIDTH)
    blue_diagonal_tiles = g.line_between(blue_start_tile, blue_end_tile)
    for tile in blue_diagonal_tiles:
        if tile.color == "green":
            tile.draw("green")
        else:
            tile.draw("blue")

    boundary_colors = {"red", "blue", "green"}
    middle_row = HEIGHT // 2

    left_yellow_seed = None
    for column in range(1, vertical_column):
        candidate_tile = Tile(middle_row, column)
        if candidate_tile.color == "white":
            left_yellow_seed = candidate_tile
            break
    left_yellow_region = []
    if left_yellow_seed is not None:
        left_yellow_region = g.fill_interior(left_yellow_seed, "yellow", boundary_colors=boundary_colors)

    right_yellow_seed = None
    for column in range(WIDTH, vertical_column, -1):
        candidate_tile = Tile(middle_row, column)
        if candidate_tile.color == "white":
            right_yellow_seed = candidate_tile
            break
    right_yellow_region = []
    if right_yellow_seed is not None:
        right_yellow_region = g.fill_interior(right_yellow_seed, "yellow", boundary_colors=boundary_colors)

    top_row = 1
    bottom_row = HEIGHT

    top_left_orange_seed = None
    for column in range(2, vertical_column):
        candidate_tile = Tile(top_row, column)
        if candidate_tile.color == "white":
            top_left_orange_seed = candidate_tile
            break
    top_left_orange_region = []
    if top_left_orange_seed is not None:
        top_left_orange_region = g.fill_interior(top_left_orange_seed, "orange", boundary_colors=boundary_colors)

    top_right_orange_seed = None
    for column in range(WIDTH - 1, vertical_column, -1):
        candidate_tile = Tile(top_row, column)
        if candidate_tile.color == "white":
            top_right_orange_seed = candidate_tile
            break
    top_right_orange_region = []
    if top_right_orange_seed is not None:
        top_right_orange_region = g.fill_interior(top_right_orange_seed, "orange", boundary_colors=boundary_colors)

    bottom_left_purple_seed = None
    for column in range(2, vertical_column):
