from hexagen import Game, Tile
from constants import HEIGHT, WIDTH, COLORS, DIRECTIONS
with Game() as g:
    column_10_green = []
    for row in range(1, HEIGHT + 1):
        tile = Tile(row, 10)
        tile.draw("green")
        column_10_green.append(tile)

    blue_diagonal_down_right = g.ray((1, 1), "down_right")
    for tile in blue_diagonal_down_right:
        if tile.color != "green":
            tile.draw("blue")

    red_diagonal_up_right = g.ray((HEIGHT, 1), "up_right")
    for tile in red_diagonal_up_right:
        if tile.color != "green":
            tile.draw("red")

    boundary_colors = {"green", "blue", "red"}
    triangle_regions = []
    for row in range(1, HEIGHT + 1):
        for col in range(1, WIDTH + 1):
            tile = Tile(row, col)
            if tile.color == "white":
                region_tiles = g.fill_interior(tile, "black", boundary_colors=boundary_colors)
                if region_tiles:
                    triangle_regions.append(region_tiles)
                    boundary_colors.add("black")

    for region_tiles in triangle_regions:
        region_size = len(region_tiles)
        if region_size in (36, 28):
            target_color = "yellow"
        elif region_size == 16:
            target_color = "orange"
        elif region_size == 20:
            target_color = "purple"
        else:
            continue
        for tile in region_tiles:
            tile.draw(target_color)

    board_state = g.board_state
